import android.content.Context
import android.content.SharedPreferences
import android.util.Base64

class AuthenticationManager(private val context: Context) {
    private val prefsName = "auth_manager_prefs"
    private val prefs: SharedPreferences by lazy { context.getSharedPreferences(prefsName, Context.MODE_PRIVATE) }

    fun saveAuthToken(authToken: String, userId: String) {
        val encodedAuth = Base64.encodeToString("$userId:$authToken".toByteArray(), Base64.NO_WRAP)
        prefs.edit().putString("auth_token", encodedAuth).apply()
    }

    fun getAuthToken(): String? {
        return prefs.getString("auth_token", null)?.let { decoded ->
            try {
                val (userId, token) = Base64.decode(decoded, Base64.NO_WRAP).split(':')
                token
            } catch (e: Exception) {
                null
            }
        }
    }

    fun saveUserId(userId: String) {
        prefs.edit().putString("user_id", userId).apply()
    }

    fun getUserId(): String? = prefs.getString("user_id", null)
}

